SELECT SUM(co2_emissions) AS total_co2_emissions
FROM emission_projections
WHERE scenario_id = 0;

SELECT retirement_id, source_id, year, ROUND(retirement_mw, 2) AS retirement_mw_rounded
FROM capacity_retirements
WHERE reason_for_retirement = 'age';

SELECT scenario_id, SUM(co2_emissions) AS total_co2_emissions
FROM emission_projections
GROUP BY scenario_id;

SELECT MAX(retirement_mw) AS max_retirement_capacity
FROM capacity_retirements
WHERE year = 2023;

SELECT SUM(retirement_mw) AS total_retirement_capacity
FROM capacity_retirements
WHERE source_id = 0;

SELECT MAX(retirement_mw) AS max_retirement_capacity
FROM capacity_retirements
WHERE year = 2025;

SELECT year, co2_emissions
FROM emission_projections
WHERE scenario_id = 0;
